def parse_headers(header_kv_list):
    headers = {}
    for kv in header_kv_list or []:
        if "=" not in kv:
            raise ValueError(f"Invalid header format '{kv}', expected key=value")
        k, v = kv.split("=", 1)
        headers[k] = v
    return headers


